oxy_webhelp_navlinks = {"rsc_cluster_registration-d30753e3170":{"topics":[{"title":"Registering Rubrik clusters using the online method","shortdesc":"<p class=\"shortdesc\">Register your Rubrik cluster using the online method to connect it to <span class=\"ph\">Rubrik Security Cloud<\/span> for centralized management and entitlement activation.<\/p>","href":"install\/registering_clusters_online.html","attributes":{"data-id":"registering_clusters_online"},"menu":{"hasChildren":false},"tocID":"registering_clusters_online-d30753e3184","next":"registering_clusters_online-d30753e3184"},{"title":"Registering Rubrik clusters using the offline method","shortdesc":"<p class=\"shortdesc\">Use the offline registration method when the Rubrik cluster cannot establish a         connection with <span class=\"ph\">Rubrik Security Cloud<\/span>.<\/p>","href":"install\/registering_clusters_offline.html","attributes":{"data-id":"registering_clusters_offline"},"menu":{"hasChildren":false},"tocID":"registering_clusters_offline-d30753e3209","topics":[]},{"title":"Resolving cluster registration issues","shortdesc":"<p class=\"shortdesc\">Provide the Rubrik Support team with secure, time-limited access to the cluster for         help resolving issues encountered during Rubrik cluster registration with <span class=\"ph\">Rubrik Security Cloud<\/span>.<\/p>","href":"install\/rsc_resolving_cluster_regn_issues.html","attributes":{"data-id":"rsc_resolving_cluster_regn_issues"},"menu":{"hasChildren":false},"tocID":"rsc_resolving_cluster_regn_issues-d30753e3223","topics":[]},{"title":"Unified Rubrik cluster registration","shortdesc":"<p class=\"shortdesc\">The unified cluster registration process applies to all types of Rubrik cluster         deployments.<\/p>","href":"install\/rsc_unified_cluster_regn.html","attributes":{"data-id":"rsc_unified_cluster_regn"},"menu":{"hasChildren":false},"tocID":"rsc_unified_cluster_regn-d30753e3237","topics":[]}]}};